mkdir -p deeptools; for bed_file in /sc/lyc/index/mouse/ref/LINE_bed/L1/*.bed; do prefix=$(basename "${bed_file}" .bed); computeMatrix scale-regions -p 40 --missingDataAsZero  --skipZeros  --beforeRegionStartLength 3000 --regionBodyLength 5000 --afterRegionStartLength 3000 --binSize 50 -R "${bed_file}" -S 1DO.bw 1AO.bw 2DO.bw 2AO.bw -o l1_repname/orf2p_${prefix}_matrix.mat.gz; [ $? -eq 0 ] && echo "处理完成: ${bed_file}" || echo "处理失败: ${bed_file}"; done
